// Publish dates (ISO) keyed by slug.
export const articleDates: Record<string, string> = {
  "kitchen-remodel-cost-tampa-bay": "2026-06-20",
  "bathroom-remodel-cost-pinellas": "2026-06-13",
  "quartz-vs-granite-vs-quartzite": "2026-06-06",
  "best-flooring-for-florida-homes": "2026-05-30",
  "cabinet-refacing-vs-replacement": "2026-05-23",
  "aging-in-place-bathroom-guide": "2026-05-16",
};

export function getArticle(slug: string): BlogArticle | undefined {
  return blogArticles.find((a) => a.slug === slug);
}

export function articleDate(slug: string): string {
  return articleDates[slug] || "2026-05-01";
}

export function articleDisplayDate(slug: string): string {
  const d = new Date(articleDate(slug) + "T12:00:00Z");
  return d.toLocaleDateString("en-US", { month: "long", year: "numeric", timeZone: "UTC" });
}

